import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import "../App.css";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleLogin = (e) => {
    e.preventDefault();

    // 🔹 ADMIN LOGIN (demo)
    if (email === "admin@retail.com" && password === "admin123") {
      localStorage.setItem("role", "admin");
      localStorage.setItem("token", "demo-admin-token");
      navigate("/admin/dashboard");
      return;
    }

    // 🔹 STAFF LOGIN (demo)
    if (email === "staff@retail.com" && password === "staff123") {
      localStorage.setItem("role", "staff");
      localStorage.setItem("token", "demo-staff-token");
      navigate("/staff/dashboard");
      return;
    }

    // ❌ Invalid
    alert("Invalid email or password");
  };

  return (
    <>
      <Navbar variant="minimal" />

      <div className="login-container">
        <div className="login-card glass">
          <h2>Login to RetailVision</h2>

          {/* DEMO INFO (sir ke liye helpful) */}
          <p className="note" style={{ marginBottom: "12px" }}>
            <strong>Demo Credentials:</strong><br />
            Admin → admin@retail.com / admin123<br />
            Staff → staff@retail.com / staff123
          </p>

          <form onSubmit={handleLogin}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />

            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />

            <button type="submit" className="login-btn">
              Login
            </button>
          </form>

          <p className="note">
            New user? <Link to="/signup">Create an account</Link>
          </p>
        </div>
      </div>
    </>
  );
}

export default Login;
